@app.route('/api/model/download', methods=['GET'])
def download_model():
    """Download the trained model."""
    model_path = os.path.join(MODEL_FOLDER, 'latest_model.keras')
    if not os.path.exists(model_path):
        return jsonify({'error': 'No trained model available'}), 404

    return send_file(model_path, as_attachment=True, download_name='model.keras')


@app.route('/api/training/status', methods=['GET'])
def training_status():
    """Check current training status."""
    return jsonify({
        'is_training': model_manager.is_training,
        'last_training': model_manager.training_history[-1] if model_manager.training_history else None,
        'total_trainings': len(model_manager.training_history)
    })


@app.route('/api/contributions/stats', methods=['GET'])
def contribution_stats():
    """Get statistics about community contributions."""
    stats = {
        'total_contributions': 0,
        'classes': {},
        'contributors': {}
    }

    log_path = os.path.join(DATA_FOLDER, 'contributions.json')
    if os.path.exists(log_path):
        with open(log_path, 'r') as f:
            contributions = json.load(f)
            stats['total_contributions'] = len(contributions)

            for contrib in contributions:
                label = contrib.get('label', 'unknown')
                contributor = contrib.get('contributor_id', 'anonymous')

                stats['classes'][label] = stats['classes'].get(label, 0) + 1
                stats['contributors'][contributor] = stats['contributors'].get(contributor, 0) + 1

    # Also count files in data folder
    for label_name in os.listdir(DATA_FOLDER):
        label_dir = os.path.join(DATA_FOLDER, label_name)
        if os.path.isdir(label_dir):
            num_files = len([f for f in os.listdir(label_dir) if allowed_file(f)])
            if label_name not in stats['classes']:
                stats['classes'][label_name] = num_files

    return jsonify(stats)


@app.route('/api/model/reset', methods=['POST'])
def reset_model():
    """Reset the model (requires confirmation)."""
    confirm = request.form.get('confirm', 'false')
    if confirm.lower() != 'true':
        return jsonify({'error': 'Confirmation required. Set confirm=true'}), 400

    if model_manager.is_training:
        return jsonify({'error': 'Cannot reset while training is in progress'}), 409

    model_manager.model = None
    model_manager.label_map = {}
    model_manager.reverse_label_map = {}
    model_manager.num_classes = 0
    model_manager._save_metadata()

    model_path = os.path.join(MODEL_FOLDER, 'latest_model.keras')
    if os.path.exists(model_path):
        os.remove(model_path)

    return jsonify({'message': 'Model reset successfully'})


